const obs = new IntersectionObserver((entries) => {
  entries.forEach(e => { if(e.isIntersecting) { e.target.style.animationPlayState = 'running'; obs.unobserve(e.target); }});
}, {threshold: 0.15});
document.querySelectorAll('.fade-up,.fade-in,.slide-left,.slide-right').forEach(el => {
  el.style.animationPlayState = 'paused';
  obs.observe(el);
});

/* ─────────────────────────────────────────── */

var lineAudios = [
  new Audio("audio/line_01.mp3"),
  new Audio("audio/line_02.mp3"),
  new Audio("audio/line_03.mp3"),
  new Audio("audio/line_04.mp3"),
  new Audio("audio/line_05.mp3"),
  new Audio("audio/line_06.mp3"),
];
var currentAudio = null;
var audioPlaying = false;
var convTimeout  = null;

var sarahConversation = [
  { speaker: 'ai',    text: "Hello Sarah, this is Ellie, your virtual assistant for EnlivenHealth Pharmacy. How can I help you today?" },
  { speaker: 'sarah', text: "I would like to check my prescription status" },
  { speaker: 'ai',    text: "Here’s the status of your prescriptions: Lisinopril 10mg is Ready for Pickup, and Atorvastatin 20mg is Eligible for Refill. Would you like to refill any of these?" },
  { speaker: 'sarah', text: "I would also like a refill for my Atorvastatin prescription" },
  { speaker: 'ai',    text: "Your Atorvastatin refill has been submitted. You will receive a notification when it is ready for pickup. Is there anything else I can help you with?" },
  { speaker: 'sarah', text: "No, that would be all." }
];

function stopConversation() {
  audioPlaying = false;
  if (convTimeout) { clearTimeout(convTimeout); convTimeout = null; }
  if (currentAudio) { currentAudio.pause(); currentAudio.currentTime = 0; currentAudio.onended = null; currentAudio = null; }
  document.getElementById('audio-btn').innerHTML = '<svg viewBox="0 0 24 24"><polygon points="5 3 19 12 5 21 5 3"/></svg>';
  document.getElementById('audio-status').innerHTML = '';
}

function toggleConversation() {
  if (audioPlaying) { stopConversation(); return; }
  audioPlaying = true;
  document.getElementById('audio-btn').innerHTML = '<svg viewBox="0 0 24 24"><rect x="6" y="4" width="4" height="16" rx="1"/><rect x="14" y="4" width="4" height="16" rx="1"/></svg>';
  playLine(0);
}

function playLine(idx) {
  if (!audioPlaying || idx >= sarahConversation.length) {
    stopConversation();
    document.getElementById('audio-status').textContent = idx >= sarahConversation.length ? 'Conversation ended' : '';
    return;
  }
  var line = sarahConversation[idx];
  var isAI = line.speaker === 'ai';
  var label = isAI ? 'Ellie (AI)' : 'Sarah Thompson';
  document.getElementById('audio-status').innerHTML = label + ' speaking<span class="speaking-indicator"><span></span><span></span><span></span></span>';

  var el = lineAudios[idx];
  currentAudio = el;
  el.currentTime = 0;
  el.onended = function() {
    if (!audioPlaying) return;
    document.getElementById('audio-status').innerHTML = '';
    convTimeout = setTimeout(function() { playLine(idx + 1); }, 500);
  };
  el.play().catch(function() { playLine(idx + 1); });
}

function openLightbox(imgEl) {
  stopConversation();
  var overlay = document.getElementById('lightbox');
  var lbImg   = document.getElementById('lightbox-img');
  var caption = document.getElementById('lightbox-caption');
  var audioPanel = document.getElementById('lightbox-audio');
  lbImg.src = imgEl.src;
  lbImg.alt = imgEl.alt;
  var card = imgEl.closest('.persona');
  var name = card ? card.querySelector('h4') : null;
  var tag  = card ? card.querySelector('.role-tag') : null;
  caption.textContent = (tag ? tag.textContent + ' — ' : '') + (name ? name.textContent : '');
  var isSarah = name && (name.textContent.indexOf('Sarah') !== -1 || name.textContent.indexOf('sarah') !== -1);
  audioPanel.classList.toggle('visible', isSarah);
  document.getElementById('audio-status').textContent = '';
  overlay.classList.add('active');
  document.body.style.overflow = 'hidden';
}

function closeLightbox() {
  stopConversation();
  document.getElementById('lightbox').classList.remove('active');
  document.body.style.overflow = '';
}

document.addEventListener('keydown', function(e) {
  if (e.key === 'Escape') closeLightbox();
});

